PROCEDURE calculateBonus(salary, rate)
{
  bonus ← salary * rate
  RETURN(bonus)
}

// This procedure computes an employee's bonus
// salary: annual salary in dollars
// rate: bonus percentage as a decimal (e.g., 0.1 for 10%)
pay ← calculateBonus(50000, 0.1)
DISPLAY(pay)

PROCEDURE isEven(n)
{
  IF(n MOD 2 = 1)
  {
    RETURN(TRUE)
  }
  ELSE
  {
    RETURN(FALSE)
  }
}

PROCEDURE checkAge(age)
{
  IF(age >= 18)
  {
    DISPLAY("Adult")
  }
  IF(age >= 13 AND age < 18)
  {
    DISPLAY("Teen")
  }
  IF(age < 13)
  {
    DISPLAY("Child")
  }
}

PROCEDURE countEvens(numList)
{
  count ← 0
  FOR EACH n IN numList
  {
    IF(n MOD 2 = 0)
    {
      count ← count + 1
    }
  }
  RETURN(count)
}

result ← countEvens([1, 2, 3, 4, 5, 6])
DISPLAY(result)

