PROCEDURE absolute(n)
{
  IF(n < 0)
  {
    RETURN(n * -1)
  }
  RETURN(n)
}

DISPLAY(absolute(-5))
DISPLAY(absolute(3))
DISPLAY(absolute(0))

PROCEDURE mystery(a, b)
{
  temp ← a MOD b
  REPEAT UNTIL(temp = 0)
  {
    a ← b
    b ← temp
    temp ← a MOD b
  }
  RETURN(b)
}

DISPLAY(mystery(12, 8))

PROCEDURE findMin(numList)
{
  min ← numList[1]
  FOR EACH item IN numList
  {
    IF(item < min)
    {
      min ← item
    }
  }
  RETURN(min)
}

DISPLAY(findMin([8, 3, 7, 1, 5]))

