PROCEDURE classify(n)
{
  IF(n > 0)
  {
    DISPLAY("Positive")
  }
  ELSE
  {
    IF(n < 0)
    {
      DISPLAY("Negative")
    }
    ELSE
    {
      DISPLAY("Zero")
    }
  }
}

classify(0)
classify(-3)
classify(7)

