PROCEDURE sumList(aList)
{
  total ← 0
  i ← 1
  REPEAT LENGTH(aList) TIMES
  {
    total ← total + aList[i]
    i ← i + 1
  }
  RETURN(total)
}

DISPLAY(sumList([4, 7, 2, 9]))

flag ← TRUE
IF(flag)
{
  DISPLAY("Flag is true")
}
flag ← NOT flag
IF(flag)
{
  DISPLAY("Still true")
}
ELSE
{
  DISPLAY("Now false")
}

PROCEDURE power(base, exp)
{
  result ← 1
  REPEAT exp TIMES
  {
    result ← result * base
  }
  RETURN(result)
}

DISPLAY(power(3, 4))
